import React, { useState } from 'react';
import './App.css';
import InputForm from './components/InputForm';

function App() {
  const [report, setReport] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false); // New state to track 'Working' status

  // New function that simulates 'Processing' before showing results
  const simulateAIProcessing = (data) => {
    setIsProcessing(true); // 1. Start simulation
    setReport(null); // 2. Clear old report (Optional, for better visual effect)
    
    // Simulate complex calculation or API delay
    setTimeout(() => {
      setReport(data); // 3. Show final report smoothly
      setIsProcessing(false); // 4. Finish simulation
    }, 1500); // Wait 1.5 seconds (adjust for realistic feel)
  };

  return (
    <div className="App">
      <h1>Performance Predictor <span className="status-warning">AI</span></h1>
      
      <div className="form-container">
        {/* Pass the function that starts simulation */}
        <InputForm setReport={simulateAIProcessing} isProcessing={isProcessing} />
      </div>

      {report && (
        <div className="report-card">
          <div className="score-display">
            {/* 1. STATUS GLOW / PILL (VISUAL SIGNAL) */}
            {/* We dynamically use pClass and pLabel from backend data */}
            <div className={`status-pill ${report.visual.pClass}`}>{report.visual.pLabel}</div>
            <div className={`score-visualizer ${report.visual.pClass}`}>
              {report.score}%
            </div>
            <p style={{color: 'var(--text-muted)', fontSize: '0.875rem'}}>Predicted Performance Index</p>
          </div>
          
          <div className="insights-container">
            {/* 2. BOLD AREAS OF IMPROVE */}
            <h3 className="insights-header">Personalized Priority Action Areas:</h3>
            <div className="insights-list">
              {report.insights.map((msg, i) => (
                <div key={i} className="insight-item">
                  {/* We make the first few words bold for instant readability */}
                  <strong>Insight {i+1}:</strong> {msg}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
